// // This module decodes a 6-bit input to a 64-bit output with all bits set except for the one corresponding to the input value.
module decoder_6to64(
    input  [5:0] data_in,
    output reg [63:0] data_out
);

always @(*) begin
    data_out = 64'b0;
    data_out[data_in] = 1'b1;
end

endmodule
